import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void alreadySortedOnePas() {
        // Sorted array: first pass finds 0 swaps immediately → 1 pass
        assertEquals(1, new Solution().passesNeeded(new int[]{1, 2, 3}));
    }

    @Test
    void emptyArray() {
        // Empty input → 1 pass (zero-swap pass terminates immediately)
        assertEquals(1, new Solution().passesNeeded(new int[]{}));
    }

    @Test
    void singleElement() {
        // Single element: one pass, zero swaps → 1
        assertEquals(1, new Solution().passesNeeded(new int[]{42}));
    }

    @Test
    void reversedTwoElements() {
        // [2,1]: pass1 swaps → [1,2]; pass2 no swaps → 2 passes total
        assertEquals(2, new Solution().passesNeeded(new int[]{2, 1}));
    }

    @Test
    void reversedThreeElements() {
        // [3,2,1]:
        // Pass1: (3>2)→swap→[2,3,1]; (3>1)→swap→[2,1,3]; swapped=true
        // Pass2: (2>1)→swap→[1,2,3]; (2<3)→no; swapped=true
        // Pass3: (1<2)→no; (2<3)→no; swapped=false → stop
        // Returns 3
        assertEquals(3, new Solution().passesNeeded(new int[]{3, 2, 1}));
    }

    @Test
    void nearSortedOneOutOfPlace() {
        // [1,3,2,4]: only one adjacent pair out of order
        // Pass1: (1<3)no; (3>2)→swap→[1,2,3,4]; (3<4)no; swapped=true
        // Pass2: no swaps → stop → 2 passes
        assertEquals(2, new Solution().passesNeeded(new int[]{1, 3, 2, 4}));
    }

    @Test
    void allSameElements() {
        // All equal: no swaps in the first pass → 1 pass
        assertEquals(1, new Solution().passesNeeded(new int[]{5, 5, 5, 5}));
    }
}
